import type { DocumentId, SummaryId, TenantId, UserId } from '@/lib/types';
import { toSummaryId } from '@/lib/types';

export type Summary = {
  id: SummaryId;
  tenantId: TenantId;
  documentId: DocumentId;
  title: string;
  shortSummary: string;
  fullSummary: string;
  createdAt: Date;
  createdBy: UserId;
};

export type CreateSummaryPayload = {
  documentId: DocumentId;
  title: string;
  shortSummary: string;
  fullSummary: string;
  createdBy: UserId;
};

const store = new Map<string, Summary>();

function key(tenantId: TenantId, summaryId: SummaryId): string {
  return `${tenantId}:${summaryId}`;
}

let idCounter = 0;
function nextId(): SummaryId {
  return toSummaryId(`sum_${Date.now()}_${++idCounter}`);
}

export function createSummary(
  tenantId: TenantId,
  payload: CreateSummaryPayload
): Summary {
  const id = nextId();
  const summary: Summary = {
    id,
    tenantId,
    documentId: payload.documentId,
    title: payload.title,
    shortSummary: payload.shortSummary,
    fullSummary: payload.fullSummary,
    createdAt: new Date(),
    createdBy: payload.createdBy,
  };
  store.set(key(tenantId, id), summary);
  return summary;
}

export function getSummary(
  tenantId: TenantId,
  summaryId: SummaryId
): Summary | undefined {
  return store.get(key(tenantId, summaryId));
}

export function listSummaries(tenantId: TenantId): Summary[] {
  const prefix = `${tenantId}:`;
  const list: Summary[] = [];
  for (const [, v] of store) {
    if (v.tenantId === tenantId) list.push(v);
  }
  return list.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
}

export function listSummariesByDocument(
  tenantId: TenantId,
  documentId: DocumentId
): Summary[] {
  return listSummaries(tenantId).filter((s) => s.documentId === documentId);
}
