import type { DocumentId, TenantId, UserId } from '@/lib/types';
import { toDocumentId } from '@/lib/types';

export type DocumentStatus = 'UPLOADED' | 'PARSING' | 'PARSED' | 'FAILED';

export type Document = {
  id: DocumentId;
  tenantId: TenantId;
  userId: UserId;
  storageUrl: string;
  storageKey: string;
  originalFilename: string;
  mimeType: string;
  sizeBytes: number;
  status: DocumentStatus;
  createdAt: Date;
  updatedAt: Date;
};

export type CreateDocumentPayload = {
  userId: UserId;
  storageUrl: string;
  storageKey: string;
  originalFilename: string;
  mimeType: string;
  sizeBytes: number;
};

const store = new Map<string, Document>();

function key(tenantId: TenantId, documentId: DocumentId): string {
  return `${tenantId}:${documentId}`;
}

let idCounter = 0;
function nextId(): DocumentId {
  return toDocumentId(`doc_${Date.now()}_${++idCounter}`);
}

export function createDocument(
  tenantId: TenantId,
  payload: CreateDocumentPayload
): Document {
  const id = nextId();
  const now = new Date();
  const doc: Document = {
    id,
    tenantId,
    userId: payload.userId,
    storageUrl: payload.storageUrl,
    storageKey: payload.storageKey,
    originalFilename: payload.originalFilename,
    mimeType: payload.mimeType,
    sizeBytes: payload.sizeBytes,
    status: 'UPLOADED',
    createdAt: now,
    updatedAt: now,
  };
  store.set(key(tenantId, id), doc);
  return doc;
}

export function getDocument(
  tenantId: TenantId,
  documentId: DocumentId
): Document | undefined {
  return store.get(key(tenantId, documentId));
}

export function listDocuments(tenantId: TenantId): Document[] {
  const prefix = `${tenantId}:`;
  const docs: Document[] = [];
  for (const [k, v] of store) {
    if (k.startsWith(prefix)) docs.push(v);
  }
  return docs.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
}

export function updateDocumentStatus(
  tenantId: TenantId,
  documentId: DocumentId,
  status: DocumentStatus
): Document | undefined {
  const doc = store.get(key(tenantId, documentId));
  if (!doc) return undefined;
  doc.status = status;
  doc.updatedAt = new Date();
  return doc;
}
