import { createRouteHandler } from "uploadthing/next";
import { ourFileRouter, OurFileRouter } from "./core";
import { appendFileSync } from "fs";
import { join } from "path";

const handler = createRouteHandler({
    router: ourFileRouter,
});

function logToFile(message: string, data: Record<string, unknown>) {
  try {
    const logPath = join(process.cwd(), "debug-63ec46.log");
    const line = JSON.stringify({ sessionId: "63ec46", location: "route.ts", message, data, timestamp: Date.now() }) + "\n";
    appendFileSync(logPath, line);
  } catch (e) {
    const errPath = join(process.cwd(), "debug-63ec46-err.log");
    appendFileSync(errPath, String(e) + "\n");
  }
}

export const GET = handler.GET;
export async function POST(req: Request, context: unknown) {
  // #region agent log
  logToFile("POST uploadthing route hit", {
    hypothesisId: "H0",
    hasClerkPublishable: !!process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY,
    hasClerkSecret: !!process.env.CLERK_SECRET_KEY,
    hasUploadThingToken: !!process.env.UPLOADTHING_TOKEN,
    cwd: process.cwd(),
  });
  // #endregion
  return handler.POST(req, context);
}