import { UploadThingError } from 'uploadthing/server';
import { createUploadthing, type FileRouter } from 'uploadthing/next';
import { currentUser } from '@clerk/nextjs/server';
import { createDocument } from '@/lib/services/documents';
import { createSummary } from '@/lib/services/summaries';
import { toUserId, toTenantId } from '@/lib/types';

const f = createUploadthing();

export const ourFileRouter = {
  pdfUploader: f({ pdf: { maxFileSize: '32MB' } })
    .middleware(async () => {
      const user = await currentUser();
      if (!user) throw new UploadThingError('Unauthorized');
      return { userId: user.id };
    })
    .onUploadComplete(async ({ metadata, file }) => {
      // #region agent log
      fetch('http://127.0.0.1:7802/ingest/999406e5-7603-41a1-a2f5-61eccfa7323e',{method:'POST',headers:{'Content-Type':'application/json','X-Debug-Session-Id':'63ec46'},body:JSON.stringify({sessionId:'63ec46',location:'core.ts:onUploadComplete',message:'env check',data:{hasClerkPublishable:!!process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY,hasClerkSecret:!!process.env.CLERK_SECRET_KEY,hasUploadThingToken:!!process.env.UPLOADTHING_TOKEN},timestamp:Date.now(),hypothesisId:'H1'})}).catch(()=>{});
      // #endregion
      try {
        const userId = toUserId(metadata.userId);
        const tenantId = toTenantId(metadata.userId);
        const doc = createDocument(tenantId, {
          userId,
          storageUrl: file.url,
          storageKey: file.key,
          originalFilename: file.name,
          mimeType: file.type ?? 'application/pdf',
          sizeBytes: file.size,
        });
        createSummary(tenantId, {
          documentId: doc.id,
          title: file.name,
          shortSummary: 'Summary will be generated after processing.',
          fullSummary: 'Full summary will appear here once the AI pipeline is connected.',
          createdBy: userId,
        });
        return { userId: metadata.userId, fileKey: file.key, fileUrl: file.url };
      } catch (err) {
        // #region agent log
        fetch('http://127.0.0.1:7802/ingest/999406e5-7603-41a1-a2f5-61eccfa7323e',{method:'POST',headers:{'Content-Type':'application/json','X-Debug-Session-Id':'63ec46'},body:JSON.stringify({sessionId:'63ec46',location:'core.ts:onUploadComplete:catch',message:'handler error',data:{errorMessage:err instanceof Error ? err.message : String(err)},timestamp:Date.now(),hypothesisId:'H2'})}).catch(()=>{});
        // #endregion
        throw err;
      }
    }),
} satisfies FileRouter;

export type OurFileRouter = typeof ourFileRouter;